var e=JSON.parse(`[{"id":"L1_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그래서 안나 맥크레디 부인을 살해했소? 내버려 둘 수 없다는 이유로?","JPN":"それでアンナ・マクレディー夫人を殺したのか？　放っておけないという理由で？","ENG":"Is that why you murdered Mrs. Anna MacCready? For this exact reason?","TWN":"所以你才殺害了安娜·麥克蕾蒂夫人嗎？因為不能放任不管？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"적당히 하시죠! 어머니는 제가 도착했을 때 이미 돌아가신 뒤였습니다!","JPN":"いい加減にしなさい！　母は私が到着した時にはすでに亡くなっていました！","ENG":"Enough! Mother was already dead when I arrived!","TWN":"請你慎言！母親在我到達時就已經去世了！"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하지만 살아 있었지. 어떤 형태로든 말이야.","JPN":"だが生きていた。どんな形であろうと。","ENG":"But she was alive... in a sense.","TWN":"但是還活著吧，以某種形式。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"대화는 나눠 보셨소? 설득하려는 시도는?","JPN":"会話はしてみたのか？　説得の試みは？","ENG":"Did you try talking to her? Persuading her?","TWN":"你跟她交談了嗎？試著說服她了嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하나뿐인 모친을 살해하고 학회를 차지한 게, 부학회장이 말한 정론이오?","JPN":"たった一人の母親を殺して学会を手に入れることが、副学会長の主張する正論なのか？","ENG":"Is your version of the \\"truth\\" murdering your own flesh and blood to obtain the Society, Vice President?","TWN":"殺害唯一的母親並獨佔學會，就是副學會長口中的正確主張嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그런 의도는…….","JPN":"そ、そんなつもりは……","ENG":"I-I had no intention of...","TWN":"我…我沒那麼想……"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그만하시죠, 하이드리히 소장님. 모처럼의 회동인데 분위기가 말이 아니네요.","JPN":"おやめください、ハイドリヒ所長。せっかくの会合なのにひどい雰囲気です。","ENG":"That'll do, Chief Heydrich. This is our first meeting in ages, and you are ruining the whole mood.","TWN":"別再說了，海德里希所長。難得召開會議，需要把氣氛搞成這樣嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아니면 혹시 안나 부인에게 가진 개인적인 감정 때문에 그러시나요?","JPN":"それとも、アンナ夫人に個人的な感情でも？","ENG":"Or are you behaving this way because of your personal feelings towards the late Anna MacCready?","TWN":"還是說因為你對安娜夫人的私人感情才會這樣？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"고지식한 생물학부장님께서 그분과 의외로 깊은 사이셨다는 풍문도 돌던데요.","JPN":"生真面目な生物学部長が、あの方と意外と深い関係だったという噂もありましたしね。","ENG":"There's a rumor that the inflexible Dean of Biology had quite an intimate relationship with her.","TWN":"有傳聞說，固執的生物學院院長和那位的關係出乎意料地深厚。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"……흥. 소문 따위나 주워 들을 시간에 발렌티누스의 비원에나 전념하지 그랬소?","JPN":"……ふん。噂話に割く時間があるなら、バレンチヌスの悲願にでも専念したらどうだ？","ENG":"...Hmph. If you have the time to listen to rumors, why not devote it to Valentinus's ambitious goal?","TWN":"……哼，有時間去聽那些傳聞，你難道不應該專注於聖華倫的事上嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아니면 객기 부리던 수도원장처럼 종탑에 목을 매달고 싶어진 건가?","JPN":"それとも調子に乗っていた修道院長のように、鐘塔で首を吊りたくなったか？","ENG":"Or do you also wish to hang yourself from the bell towers like that misguided former abbot?","TWN":"還是說你想像意氣用事的修道院院長那樣吊死在鐘塔上？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아직까지는요. 생각이 바뀌면 연락드리죠.","JPN":"いいえ、まだ。気が変わったら連絡さしあげます。","ENG":"Not yet. But I will contact you if I change my mind.","TWN":"目前還不想。等我改變主意了就聯絡你。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 토론의 장에서 협박은 썩 좋은 수단 같지 않은걸요.","JPN":"でも、議論の場で脅しはあまりいい手段ではないと思いますよ。","ENG":"But intimidation seems to be a foolish tactic in a debate setting like this.","TWN":"不過在討論場合，威脅似乎不是什麼好手段吧。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};